from contextlib import contextmanager
from io import StringIO
import sys
import os


class StreamTTY(StringIO):
    def isatty(self):
        """Return True to indicate this stream behaves like a TTY."""
        return True

class StreamNonTTY(StringIO):
    def isatty(self):
        """Return False to indicate this stream does not behave like a TTY."""
        return False

@contextmanager
def osname(name):
    """Temporarily set os.name to the given value within the context."""
    orig = os.name
    os.name = name
    try:
        yield
    finally:
        os.name = orig

@contextmanager
def replace_by(stream):
    """Temporarily replace sys.stdout and sys.stderr with the given stream."""
    orig_stdout = sys.stdout
    orig_stderr = sys.stderr
    sys.stdout = stream
    sys.stderr = stream
    try:
        yield
    finally:
        sys.stdout = orig_stdout
        sys.stderr = orig_stderr

@contextmanager
def replace_original_by(stream):
    """Temporarily replace sys.__stdout__ and sys.__stderr__ with the given stream."""
    orig_stdout = sys.__stdout__
    orig_stderr = sys.__stderr__
    sys.__stdout__ = stream
    sys.__stderr__ = stream
    try:
        yield
    finally:
        sys.__stdout__ = orig_stdout
        sys.__stderr__ = orig_stderr

@contextmanager
def pycharm():
    """Simulate running under PyCharm by setting PYCHARM_HOSTED and using non-TTY streams."""
    os.environ["PYCHARM_HOSTED"] = "1"
    non_tty = StreamNonTTY()
    try:
        with replace_by(non_tty), replace_original_by(non_tty):
            yield
    finally:
        os.environ.pop("PYCHARM_HOSTED", None)